cat > /tmp/inspect.csx << 'EOF'
using System;
using System.Reflection;
using System.IO;

string dllPath = Args[0];
var assembly = Assembly.LoadFrom(dllPath);

var types = assembly.GetTypes()
    .OrderBy(t => t.Namespace + "." + t.Name)
    .ToList();

Console.WriteLine($"=== Types in {Path.GetFileName(dllPath)} ===\n");

var namespaces = types.Select(t => t.Namespace).Distinct().OrderBy(ns => ns);
foreach (var ns in namespaces)
{
    Console.WriteLine($"\nNamespace: {ns}");
    var typesInNs = types.Where(t => t.Namespace == ns).OrderBy(t => t.Name);
    foreach (var type in typesInNs)
    {
        if (type.IsPublic)
        {
            var typeKind = type.IsClass ? "class" : type.IsInterface ? "interface" : type.IsEnum ? "enum" : "struct";
            Console.WriteLine($"  {typeKind} {type.Name}");

            // Show constructors for agent-related classes
            if (type.Name.Contains("Agent") || type.Name.Contains("Options") || type.Name.Contains("Tool"))
            {
                var ctors = type.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
                foreach (var ctor in ctors)
                {
                    var ps = string.Join(", ", ctor.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
                    Console.WriteLine($"    .ctor({ps})");
                }

                // Show key methods
                var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
                    .Where(m => !m.IsSpecialName && (m.Name.Contains("Invoke") || m.Name.Contains("Execute") || m.Name.Contains("Call")))
                    .OrderBy(m => m.Name);
                foreach (var method in methods)
                {
                    var ps = string.Join(", ", method.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
                    Console.WriteLine($"    {method.ReturnType.Name} {method.Name}({ps})");
                }
            }
        }
    }
}
EOF
