using System;
using System.Reflection;

// Set up assembly resolution
AppDomain.CurrentDomain.AssemblyResolve += (sender, args) => {
    var name = new AssemblyName(args.Name).Name;
    try {
        return Assembly.LoadFrom($"/home/runner/.nuget/packages/{name.ToLower()}/*/lib/net10.0/{name}.dll");
    } catch {
        return null;
    }
};

try {
    var asm = Assembly.LoadFrom("/home/runner/.nuget/packages/microsoft.agents.ai/1.8.0/lib/net10.0/Microsoft.Agents.AI.dll");

    Console.WriteLine("=== ChatClientAgent ===");
