        Console.WriteLine($"Namespace: {chatAgent.Namespace}");
        Console.WriteLine($"Class: {chatAgent.Name}");

        var ctors = chatAgent.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
        foreach (var ctor in ctors) {
            var ps = string.Join(", ", ctor.GetParameters().Select(p => p.ParameterType.Name + " " + p.Name));
            Console.WriteLine($"  ctor({ps})");
