            .OrderBy(m => m.Name);
        foreach (var m in runMethods) {
            Console.WriteLine($"  {m.ReturnType.Name} {m.Name}(...)");
        }
    }
} catch (Exception ex) {
    Console.WriteLine($"Error: {ex}");
}
EOF
