using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Tool implementations ----------------------------------------------------

var notebook = new ResearchNotebook();

var searchTool = AIFunctionFactory.Create(
    [Description("Search the web for information on a query. Returns a list of result snippets.")]
    async (
        [Description("The search query string")] string query,
        CancellationToken cancellationToken) =>
    {
        Console.WriteLine($"  🔍  Searching: \"{query}\"");
        using var http = new HttpClient();
        http.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

        var url = $"https://api.duckduckgo.com/?q={Uri.EscapeDataString(query)}&format=json&no_html=1";
        var json = await http.GetStringAsync(url, cancellationToken);
        using var doc = JsonDocument.Parse(json);

        var results = new List<string>();

        // Abstract (instant answer)
        var abs = doc.RootElement.GetProperty("Abstract").GetString();
        if (!string.IsNullOrWhiteSpace(abs))
            results.Add($"[Abstract] {abs}");

        // Related topics
        if (doc.RootElement.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var topic in topics.EnumerateArray().Take(8))
            {
                if (topic.TryGetProperty("Text", out var text))
                    results.Add(text.GetString()!);
            }
        }

        if (results.Count == 0)
            results.Add($"No detailed results found for \"{query}\". Try rephrasing.");

        return string.Join("\n---\n", results);
    },
    name: "web_search",
    description: "Search the web for information on a query. Returns a list of result snippets.");

var saveNoteTool = AIFunctionFactory.Create(
    [Description("Save a research note with a title and body text to the notebook.")]
    (
        [Description("Short title for the note")] string title,
        [Description("Body content of the note")] string content) =>
    {
        notebook.AddNote(title, content);
        Console.WriteLine($"  📝  Note saved: \"{title}\"");
        return $"Note \"{title}\" saved successfully ({notebook.Count} total notes).";
    },
    name: "save_note",
    description: "Save a research note with a title and body text to the notebook.");

var readNotesTool = AIFunctionFactory.Create(
    [Description("Read all saved research notes from the notebook.")]
    () =>
    {
        if (notebook.Count == 0)
            return "Notebook is empty. No notes saved yet.";

        return notebook.GetAllNotes();
    },
    name: "read_notes",
    description: "Read all saved research notes from the notebook.");

// --- Build the agent ---------------------------------------------------------

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a Research Agent. Your goal is to thoroughly research a topic
        provided by the user and produce a well-structured summary.

        Workflow:
        1. Break the topic into 2-4 focused sub-queries.
        2. Use the web_search tool to search for each sub-query.
        3. Use save_note to record key findings from each search (title + content).
        4. After finishing research, use read_notes to review your collected notes.
        5. Produce a final, well-organized summary with sections and key takeaways.

        Be thorough but concise. Cite the sources of specific facts when possible.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes",
    tools: [searchTool, saveNoteTool, readNotesTool],
    loggerFactory: null,
    services: null);

// --- Run the agent -----------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════╗");
