var messages = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

var session = await agent.CreateSessionAsync(conversationId: null);

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 4096,
});

var response = await agent.RunAsync(messages, session, runOptions);

Console.WriteLine();
Console.WriteLine(new string('═', 50));
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine(new string('═', 50));
Console.WriteLine();
Console.WriteLine(response.Text);
Console.WriteLine();
Console.WriteLine(new string('─', 50));
Console.WriteLine($"Notes collected: {notebook.Count}");

